import re

def count_politicians(articles, politician_names):
    # Create a set of lowercase politician names for case-insensitive matching
    lowercase_politician_names = {name.lower() for name in politician_names}

    # Initialize a dictionary to hold counts
    counts = {}

    # Process each article
    for article in articles:
        # Extract all names from the article using a regular expression
        names = re.findall(r'\b(?:\w+|\w+[\w-]*\w+)\b', article)

        # Convert names to lowercase and check against the set of politician names
        for name in names:
            if name.lower() in lowercase_politician_names:
                # Increment the count for the politician
                counts[name] = counts.get(name, 0) + 1

    return counts
